mapper.select:
select request_id, room_id, user_id, nickname, amount, status, bid_version, error_message, created_at, updated_at
from auction_bid_request
where request_id = #{requestId}

mapper.update:
update auction_bid_request
set status = 'SUCCESS',
    bid_version = #{bidVersion},
    error_message = null,
    updated_at = #{updatedAt}
where request_id = #{requestId}

update auction_bid_request
set status = 'FAILED',
    error_message = #{errorMessage},
    updated_at = #{updatedAt}
where request_id = #{requestId}
